SELECT DISTINCT CHAM.SEMESTRE FROM CALC_HORA_AULA_MEDIA CHAM JOIN SERVIDOR S ON CHAM.SIAPE = S.PK_SIAPE WHERE CHAM.ANO = 2024 AND UPPER(CHAM.SIGLA_CAMPUS) = 'URU' AND (UPPER(CHAM.AREA_INGRESSO) LIKE '%QUIMICA%' OR UPPER(CHAM.AREA_INGRESSO) LIKE '%QUIMICA%') AND UPPER(COALESCE(S.CONTRATO,'')) LIKE '%EFETIV%' ORDER BY CHAM.SEMESTRE